export default function Home() {
  const [searchTerm, setSearchTerm] = useState('');
  const [scores, setScores] = useState({});

  useEffect(() => {
    // Load scores from localStorage
    const savedScores = localStorage.getItem('thinkfast_scores');
    if (savedScores) {
      setScores(JSON.parse(savedScores));
    }
  }, []);

  const filteredCategories = quizCategories.filter(cat => 
    cat.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
    cat.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <>
      <SplashCursor />
      <div className="home-wrapper">
        {/* Premium Background Orbs */}
      <div className="bg-orb orb-1"></div>
      <div className="bg-orb orb-2"></div>
      <div className="bg-orb orb-3"></div>

      <div className="home-container">
        <header className="home-header">
          <div className="logo-container">
            <img src={logo} alt="ThinkFast Logo" className="app-logo" />
            <div className="logo-glow"></div>
          </div>
          <h1>Think<span className="text-gradient">Fast</span></h1>
          <p className="subtitle">Test your knowledge across multiple domains. 15 seconds per question. Think fast, act faster.</p>
          
          <div className="search-container">
            <input 
              type="text" 
              className="search-input" 
              placeholder="Search categories (e.g. React, Java...)" 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </header>

        <div className="categories-grid">
          {filteredCategories.length > 0 ? filteredCategories.map((category, index) => {
            const categoryScore = scores[category.id];
            
            return (
              <Link 
                to={`/quiz/${category.id}`} 
                key={category.id} 
                className="category-card glass-panel"
                style={{ '--theme-color': category.color, animationDelay: `${index * 0.1}s` }}
              >
                <div className="card-glow" style={{ background: category.color }}></div>
                <div className="category-icon" style={{ color: category.color, filter: `drop-shadow(0 0 10px ${category.color}80)` }}>
                  {getIconForCategory(category.id)}
                </div>
                <h2>{category.title}</h2>
                <p>{category.description}</p>
                <div className="card-footer">
                  {categoryScore && (
                    <div className="score-badge-small">
                      Best Score: {categoryScore.score}/{categoryScore.total}
                    </div>
                  )}
                  <span className="start-btn" style={{ backgroundColor: category.color, boxShadow: `0 4px 15px ${category.color}40` }}>Start Challenge</span>
                </div>
              </Link>
            )
          }) : (
            <div style={{ textAlign: 'center', gridColumn: '1 / -1', color: 'var(--text-muted)', padding: '2rem' }}>
              No categories found matching "{searchTerm}"
            </div>
          )}
        </div>
      </div>
    </div>
    </>
  );
}
